import{_ as a,o as i,c as t,ag as s}from"./chunks/framework.9L5wI8-n.js";const c=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"support/faq.md","filePath":"support/faq.md"}'),r={name:"support/faq.md"};function o(n,e,l,h,p,d){return i(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Frequently asked questions about AI Image Renamer.</p><h2 id="is-this-plugin-free" tabindex="-1">Is this plugin free? <a class="header-anchor" href="#is-this-plugin-free" aria-label="Permalink to &quot;Is this plugin free?&quot;">​</a></h2><p>Yes! The plugin is 100% free and open source (GPL-2.0). It uses the Groq API, which offers a generous free tier for personal and commercial use.</p><h2 id="do-i-need-a-groq-api-key" tabindex="-1">Do I need a Groq API key? <a class="header-anchor" href="#do-i-need-a-groq-api-key" aria-label="Permalink to &quot;Do I need a Groq API key?&quot;">​</a></h2><p>Yes. You need a free API key from <a href="https://console.groq.com/keys" target="_blank" rel="noreferrer">console.groq.com</a>. Registration is free and takes less than a minute. No credit card required.</p><h2 id="what-happens-if-the-api-fails" tabindex="-1">What happens if the API fails? <a class="header-anchor" href="#what-happens-if-the-api-fails" aria-label="Permalink to &quot;What happens if the API fails?&quot;">​</a></h2><p>The plugin gracefully falls back to the original filename. Your upload will <strong>never</strong> fail due to API issues — the image is always saved, just with its original name.</p><h2 id="which-ai-models-are-available" tabindex="-1">Which AI models are available? <a class="header-anchor" href="#which-ai-models-are-available" aria-label="Permalink to &quot;Which AI models are available?&quot;">​</a></h2><p>You can choose between two Llama 4 vision models:</p><ul><li><strong>Maverick</strong> — High-performance model with 128 experts, best for detailed analysis</li><li><strong>Scout</strong> — Lightweight model with 16 experts, optimized for speed</li></ul><p>Both models are free to use through Groq&#39;s API.</p><h2 id="does-this-work-with-existing-images" tabindex="-1">Does this work with existing images? <a class="header-anchor" href="#does-this-work-with-existing-images" aria-label="Permalink to &quot;Does this work with existing images?&quot;">​</a></h2><p>Currently, the plugin only processes <strong>new uploads</strong>. Bulk renaming of existing images is planned for a future Pro version.</p><h2 id="can-i-customize-the-ai-prompt" tabindex="-1">Can I customize the AI prompt? <a class="header-anchor" href="#can-i-customize-the-ai-prompt" aria-label="Permalink to &quot;Can I customize the AI prompt?&quot;">​</a></h2><p>Yes! Use the <a href="/wp-ai-image-renamer/api/filter-hooks.html#air-prompt"><code>air_prompt</code></a> filter to modify or completely replace the prompt. See the <a href="/wp-ai-image-renamer/api/examples.html">examples page</a> for code snippets.</p><h2 id="can-i-disable-renaming-for-specific-uploads" tabindex="-1">Can I disable renaming for specific uploads? <a class="header-anchor" href="#can-i-disable-renaming-for-specific-uploads" aria-label="Permalink to &quot;Can I disable renaming for specific uploads?&quot;">​</a></h2><p>Yes. You can either:</p><ol><li>Toggle <strong>&quot;Enable Auto-Rename&quot;</strong> off in the settings before uploading</li><li>Use the <a href="/wp-ai-image-renamer/api/filter-hooks.html#air-should-process-upload"><code>air_should_process_upload</code></a> filter to programmatically skip certain uploads</li></ol><h2 id="is-my-api-key-secure" tabindex="-1">Is my API key secure? <a class="header-anchor" href="#is-my-api-key-secure" aria-label="Permalink to &quot;Is my API key secure?&quot;">​</a></h2><p>Yes. API keys are encrypted using the <a href="https://github.com/defuse/php-encryption" target="_blank" rel="noreferrer"><code>defuse/php-encryption</code></a> library before being stored in the database. For maximum security, you can define your encryption key in <code>wp-config.php</code>:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;AIR_ENCRYPTION_KEY&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;your-key-here&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> );</span></span></code></pre></div><p>See the <a href="/wp-ai-image-renamer/usage/settings.html">Settings page</a> for more details.</p><h2 id="does-this-affect-site-performance" tabindex="-1">Does this affect site performance? <a class="header-anchor" href="#does-this-affect-site-performance" aria-label="Permalink to &quot;Does this affect site performance?&quot;">​</a></h2><p>The API call happens <strong>only during upload</strong> and typically takes 1–3 seconds. Regular site visitors will not notice any performance impact. There is zero frontend overhead.</p><h2 id="what-file-types-are-supported" tabindex="-1">What file types are supported? <a class="header-anchor" href="#what-file-types-are-supported" aria-label="Permalink to &quot;What file types are supported?&quot;">​</a></h2><p>JPEG, PNG, WebP, AVIF, and GIF. You can enable or disable specific types in the <a href="/wp-ai-image-renamer/usage/settings.html">settings</a>.</p><h2 id="can-i-use-this-on-multiple-sites" tabindex="-1">Can I use this on multiple sites? <a class="header-anchor" href="#can-i-use-this-on-multiple-sites" aria-label="Permalink to &quot;Can I use this on multiple sites?&quot;">​</a></h2><p>Yes! Each site needs its own configuration, but you can use the same Groq API key across multiple WordPress installations.</p><h2 id="what-data-is-sent-to-groq" tabindex="-1">What data is sent to Groq? <a class="header-anchor" href="#what-data-is-sent-to-groq" aria-label="Permalink to &quot;What data is sent to Groq?&quot;">​</a></h2><p>When you upload an image, the plugin sends:</p><ul><li>The image data (base64 encoded)</li><li>A text prompt asking the AI to describe the image</li></ul><p>This data is <strong>only</strong> sent during upload, and <strong>only</strong> for enabled file types. No data is stored on external servers by this plugin. See the <a href="https://groq.com/privacy-policy/" target="_blank" rel="noreferrer">Groq Privacy Policy</a> for how Groq handles data on their end.</p><h2 id="how-do-i-report-a-bug" tabindex="-1">How do I report a bug? <a class="header-anchor" href="#how-do-i-report-a-bug" aria-label="Permalink to &quot;How do I report a bug?&quot;">​</a></h2><p>You can report bugs through:</p><ul><li><a href="https://wordpress.org/support/plugin/ai-image-renamer/" target="_blank" rel="noreferrer">WordPress.org Support Forum</a></li><li><a href="https://github.com/thaikolja/wp-ai-image-renamer/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li></ul>',36)])])}const m=a(r,[["render",o]]);export{c as __pageData,m as default};
